INSERT INTO public.scenarios VALUES ('2025-08-12 07:52:09.879666-05','2025-12-21 08:38:39.922985-06','Aggressive Scenario','false','true','true','false','false','false','Practice scenario featuring an aggressive or confrontational student persona.','019b3be4-3c3a-7a19-90e8-cab854ab2cf8','019b3be4-3112-7685-8967-a5488fadb090','019b3be4-3112-7729-9b44-8f6834272c7b','019b3be4-3112-7759-9feb-215a25487676');
